/**
 * Winston Logger Configuration
 */

const winston = require('winston');
const path = require('path');

// Define log levels
const levels = {
  error: 0,
  warn: 1,
  info: 2,
  debug: 3
};

// Define colors for each level
const colors = {
  error: 'red',
  warn: 'yellow',
  info: 'green',
  debug: 'blue'
};

winston.addColors(colors);

// Custom format
const format = winston.format.combine(
  winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
  winston.format.errors({ stack: true }),
  winston.format.splat(),
  winston.format.json()
);

// Console format (colored for development)
const consoleFormat = winston.format.combine(
  winston.format.colorize({ all: true }),
  winston.format.timestamp({ format: 'HH:mm:ss' }),
  winston.format.printf(
    info => `${info.timestamp} ${info.level}: ${info.message} ${info.stack || ''}`
  )
);

// Create transports
const transports = [];

// Console transport (always enabled)
transports.push(
  new winston.transports.Console({
    format: process.env.NODE_ENV === 'production' ? format : consoleFormat
  })
);

// File transport (only in production)
if (process.env.NODE_ENV === 'production') {
  transports.push(
    new winston.transports.File({
      filename: process.env.LOG_FILE_PATH || './logs/error.log',
      level: 'error'
    }),
    new winston.transports.File({
      filename: process.env.LOG_FILE_PATH || './logs/combined.log'
    })
  );
}

// Create logger
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  levels,
  format,
  transports,
  exitOnError: false
});

// Create stream for Morgan (HTTP logging)
logger.stream = {
  write: (message) => {
    logger.info(message.trim());
  }
};

module.exports = logger;

/**
 * Auth Middleware
 */

const jwt = require('jsonwebtoken');
const logger = require('../config/logger');

/**
 * Verificar token JWT
 */
function verifyToken(token) {
  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    return decoded;
  } catch (error) {
    throw new Error('Token inválido');
  }
}

/**
 * Gerar token JWT
 */
function generateToken(userId, plan = 'free', email = '') {
  return jwt.sign(
    { userId, plan, email },
    process.env.JWT_SECRET,
    { expiresIn: process.env.JWT_EXPIRES_IN || '24h' }
  );
}

/**
 * Gerar refresh token
 */
function generateRefreshToken(userId) {
  return jwt.sign(
    { userId, type: 'refresh' },
    process.env.JWT_REFRESH_SECRET || process.env.JWT_SECRET,
    { expiresIn: process.env.JWT_REFRESH_EXPIRES_IN || '7d' }
  );
}

/**
 * Middleware de autenticação para rotas HTTP
 */
function authenticateRequest(req, res, next) {
  try {
    const authHeader = req.headers.authorization;
    
    if (!authHeader) {
      return res.status(401).json({ error: 'Token não fornecido' });
    }

    const token = authHeader.replace('Bearer ', '');
    const decoded = verifyToken(token);
    
    req.user = {
      userId: decoded.userId,
      plan: decoded.plan
    };
    
    next();
  } catch (error) {
    logger.error('Auth error', { error: error.message });
    res.status(401).json({ error: 'Token inválido ou expirado' });
  }
}

module.exports = {
  verifyToken,
  generateToken,
  generateRefreshToken,
  authenticateRequest
};

/**
 * Plan Verification Middleware
 * Valida se o usuário tem o plano necessário para acessar features premium
 */

const logger = require('../config/logger');

/**
 * Middleware: Requer plano Premium
 * Bloqueia acesso se usuário não for Premium ou Pro
 */
function requirePremium(req, res, next) {
  try {
    const plan = req.user?.plan;

    // Log tentativa de acesso
    logger.info('Premium feature access attempt', {
      userId: req.user?.userId,
      plan,
      endpoint: req.originalUrl
    });

    // Validar plano
    if (plan !== 'premium' && plan !== 'pro') {
      logger.warn('Premium access denied', {
        userId: req.user?.userId,
        plan,
        endpoint: req.originalUrl
      });

      return res.status(403).json({
        success: false,
        error: 'Funcionalidade Premium',
        message: 'Assine Premium para acessar esta funcionalidade',
        upgrade_url: '/pricing'
      });
    }

    // Usuário tem permissão
    next();
  } catch (error) {
    logger.error('Plan check error', { error: error.message });
    res.status(500).json({
      success: false,
      error: 'Erro ao verificar plano'
    });
  }
}

/**
 * Middleware: Requer plano Pro ou superior
 */
function requirePro(req, res, next) {
  try {
    const plan = req.user?.plan;

    if (plan !== 'pro' && plan !== 'premium') {
      logger.warn('Pro access denied', {
        userId: req.user?.userId,
        plan,
        endpoint: req.originalUrl
      });

      return res.status(403).json({
        success: false,
        error: 'Funcionalidade Pro',
        message: 'Assine Pro ou Premium para acessar',
        upgrade_url: '/pricing'
      });
    }

    next();
  } catch (error) {
    logger.error('Plan check error', { error: error.message });
    res.status(500).json({
      success: false,
      error: 'Erro ao verificar plano'
    });
  }
}

/**
 * Middleware: Bloquear usuários Free (apenas Trial/Premium+)
 */
function blockFree(req, res, next) {
  try {
    const plan = req.user?.plan;

    if (plan === 'free') {
      logger.warn('Free access denied', {
        userId: req.user?.userId,
        endpoint: req.originalUrl
      });

      return res.status(403).json({
        success: false,
        error: 'Trial expirado',
        message: 'Seu período de teste expirou. Assine para continuar.',
        upgrade_url: '/pricing'
      });
    }

    next();
  } catch (error) {
    logger.error('Plan check error', { error: error.message });
    res.status(500).json({
      success: false,
      error: 'Erro ao verificar plano'
    });
  }
}

/**
 * Helper: Verificar se usuário é premium (não middleware)
 */
function isPremiumUser(user) {
  return user?.plan === 'premium' || user?.plan === 'pro';
}

/**
 * Helper: Verificar se usuário é free
 */
function isFreeUser(user) {
  return !user?.plan || user?.plan === 'free';
}

module.exports = {
  requirePremium,
  requirePro,
  blockFree,
  isPremiumUser,
  isFreeUser
};

/**
 * Error Handler Middleware
 */

const logger = require('../config/logger');

function errorHandler(err, req, res, next) {
  logger.error('Error occurred', {
    error: err.message,
    stack: err.stack,
    path: req.path,
    method: req.method
  });

  // Erro de validação
  if (err.name === 'ValidationError') {
    return res.status(400).json({
      error: 'Validation Error',
      details: err.message
    });
  }

  // Erro de autenticação
  if (err.name === 'UnauthorizedError' || err.message.includes('token')) {
    return res.status(401).json({
      error: 'Unauthorized',
      message: 'Token inválido ou expirado'
    });
  }

  // Erro genérico
  res.status(err.status || 500).json({
    error: err.message || 'Internal Server Error',
    ...(process.env.NODE_ENV === 'development' && { stack: err.stack })
  });
}

module.exports = { errorHandler };

/**
 * Rate Limiting Middleware
 * Protege contra abuso de API e ataques DDoS
 */

const rateLimit = require('express-rate-limit');
const logger = require('../config/logger');

/**
 * Rate limiter geral para API
 * DESENVOLVIMENTO: 500 requisições por 15 minutos
 * PRODUÇÃO: 100 requisições por 15 minutos
 */
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutos
  max: process.env.NODE_ENV === 'development' ? 500 : 100, // Mais permissivo em dev
  message: {
    success: false,
    error: 'Muitas requisições',
    message: 'Você excedeu o limite de requisições. Tente novamente em 15 minutos.',
    retry_after: 15 * 60 // segundos
  },
  standardHeaders: true, // Retorna info no `RateLimit-*` headers
  legacyHeaders: false, // Desabilita `X-RateLimit-*` headers
  handler: (req, res) => {
    logger.warn('Rate limit exceeded', {
      ip: req.ip,
      endpoint: req.originalUrl,
      user: req.user?.userId,
      environment: process.env.NODE_ENV
    });

    res.status(429).json({
      success: false,
      error: 'Muitas requisições',
      message: 'Você excedeu o limite de requisições. Tente novamente em 15 minutos.',
      retry_after: 15 * 60
    });
  }
});

/**
 * Rate limiter para rotas de OpenAI (CARAS!)
 * DESENVOLVIMENTO: 50 requisições por minuto (testes)
 * PRODUÇÃO: 5 requisições por minuto
 */
const openaiLimiter = rateLimit({
  windowMs: 60 * 1000, // 1 minuto
  max: process.env.NODE_ENV === 'development' ? 50 : 5, // Mais permissivo em dev
  message: {
    success: false,
    error: 'Muitas requisições',
    message: 'Aguarde antes de gerar novo caso. Limite: 5 por minuto.',
    retry_after: 60
  },
  standardHeaders: true,
  legacyHeaders: false,
  skipSuccessfulRequests: false, // Conta mesmo se sucesso
  handler: (req, res) => {
    logger.warn('OpenAI rate limit exceeded', {
      ip: req.ip,
      endpoint: req.originalUrl,
      user: req.user?.userId,
      environment: process.env.NODE_ENV
    });

    res.status(429).json({
      success: false,
      error: 'Aguarde para gerar novo caso',
      message: 'Você está gerando casos muito rápido. Aguarde 1 minuto.',
      retry_after: 60
    });
  }
});

/**
 * Rate limiter para autenticação (login/signup)
 * 10 tentativas por 15 minutos por IP
 * Previne brute force
 */
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutos
  max: 10, // 10 tentativas de login
  skipSuccessfulRequests: true, // Não conta logins bem-sucedidos
  message: {
    success: false,
    error: 'Muitas tentativas de login',
    message: 'Muitas tentativas de login. Tente novamente em 15 minutos.',
    retry_after: 15 * 60
  },
  handler: (req, res) => {
    logger.warn('Auth rate limit exceeded', {
      ip: req.ip,
      endpoint: req.originalUrl,
      email: req.body?.email
    });

    res.status(429).json({
      success: false,
      error: 'Muitas tentativas de login',
      message: 'Muitas tentativas de login. Tente novamente em 15 minutos.',
      retry_after: 15 * 60
    });
  }
});

/**
 * Rate limiter para webhooks (Kiwify, Flexifunnels)
 * 20 requisições por hora por IP
 */
const webhookLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hora
  max: 20,
  message: {
    success: false,
    error: 'Muitas requisições de webhook',
    message: 'Aguarde antes de tentar novamente.',
    retry_after: 60 * 60
  },
  handler: (req, res) => {
    logger.warn('Webhook rate limit exceeded', {
      ip: req.ip,
      user: req.user?.userId
    });

    res.status(429).json({
      success: false,
      error: 'Muitas requisições de webhook',
      message: 'Aguarde antes de tentar novamente.',
      retry_after: 60 * 60
    });
  }
});

/**
 * Rate limiter customizado por plano do usuário
 * Free: 3 req/min | Basic: 10 req/min | Premium: 30 req/min
 */
function createPlanBasedLimiter(limits = { free: 3, basic: 10, premium: 30 }) {
  return rateLimit({
    windowMs: 60 * 1000, // 1 minuto
    max: (req) => {
      const plan = req.user?.plan || 'free';
      return limits[plan] || limits.free;
    },
    keyGenerator: (req) => {
      // Usar userId ao invés de IP para usuários autenticados
      return req.user?.userId || req.ip;
    },
    handler: (req, res) => {
      const plan = req.user?.plan || 'free';
      logger.warn('Plan-based rate limit exceeded', {
        userId: req.user?.userId,
        plan,
        endpoint: req.originalUrl
      });

      res.status(429).json({
        success: false,
        error: 'Limite de plano atingido',
        message: `Limite de ${limits[plan] || limits.free} requisições/minuto atingido. Faça upgrade para aumentar.`,
        current_plan: plan,
        upgrade_url: '/pricing'
      });
    }
  });
}

module.exports = {
  apiLimiter,
  openaiLimiter,
  authLimiter,
  webhookLimiter,
  createPlanBasedLimiter
};

/**
 * Account Routes - Scopsy Lab
 * Gerenciamento de perfil e dados de assinatura
 */

const express = require('express');
const bcrypt = require('bcrypt');
const { createClient } = require('@supabase/supabase-js');
const { authenticateRequest } = require('../middleware/auth');
const logger = require('../config/logger');

const router = express.Router();

const supabase = createClient(
    process.env.SUPABASE_URL,
    process.env.SUPABASE_SERVICE_ROLE_KEY
);

/**
 * GET /api/account/me
 * Retorna dados completos do perfil + assinatura
 */
router.get('/me', authenticateRequest, async (req, res) => {
    try {
        const userId = req.user.userId;

        logger.info('[ACCOUNT] Buscando perfil completo', { userId });

        // Colunas que existem com certeza na tabela users
        const baseCols = 'id, email, name, crp, plan, subscription_status, created_at, last_login';
        // Colunas Kiwify (adicionadas via migration, podem não existir ainda)
        const kiwifyCols = ', subscription_started_at, subscription_ended_at, subscription_next_billing, kiwify_customer_id';

        let user;
        const fullQuery = await supabase
            .from('users')
            .select(baseCols + kiwifyCols)
            .eq('id', userId)
            .single();

        if (fullQuery.error && fullQuery.error.message.includes('does not exist')) {
            logger.warn('[ACCOUNT] Colunas Kiwify ausentes, usando query base', { error: fullQuery.error.message });
            const fallback = await supabase
                .from('users')
                .select(baseCols)
                .eq('id', userId)
                .single();
            if (fallback.error || !fallback.data) {
                logger.error('[ACCOUNT] Usuário não encontrado', { userId, error: fallback.error?.message });
                return res.status(404).json({ error: 'Usuário não encontrado' });
            }
            user = fallback.data;
        } else if (fullQuery.error || !fullQuery.data) {
            logger.error('[ACCOUNT] Usuário não encontrado', { userId, error: fullQuery.error?.message });
            return res.status(404).json({ error: 'Usuário não encontrado' });
        } else {
            user = fullQuery.data;
        }

        // Calcular dias restantes do trial (se free)
        let trialDaysLeft = null;
        if (user.plan === 'free' && user.created_at) {
            const createdAt = new Date(user.created_at);
            const now = new Date();
            const diffDays = Math.floor((now - createdAt) / (1000 * 60 * 60 * 24));
            trialDaysLeft = Math.max(0, 7 - diffDays);
        }

        res.json({
            user: {
                id: user.id,
                email: user.email,
                name: user.name,
                crp: user.crp || null,
                plan: user.plan,
                created_at: user.created_at,
                last_login: user.last_login
            },
            subscription: {
                status: user.subscription_status || 'inactive',
                started_at: user.subscription_started_at || null,
                ended_at: user.subscription_ended_at || null,
                next_billing: user.subscription_next_billing || null,
                kiwify_order_id: user.kiwify_customer_id || null
            },
            trial_days_left: trialDaysLeft
        });

    } catch (error) {
        logger.error('[ACCOUNT] Erro ao buscar perfil', { error: error.message });
        res.status(500).json({ error: 'Erro ao buscar dados da conta' });
    }
});

/**
 * PUT /api/account/profile
 * Atualizar nome e CRP do usuário
 */
router.put('/profile', authenticateRequest, async (req, res) => {
    try {
        const userId = req.user.userId;
        const { name, crp } = req.body;

        // Validação
        if (!name || name.trim().length < 2) {
            return res.status(400).json({ error: 'Nome deve ter no mínimo 2 caracteres' });
        }

        if (name.trim().length > 100) {
            return res.status(400).json({ error: 'Nome deve ter no máximo 100 caracteres' });
        }

        // Validar formato CRP se fornecido (XX/XXXXXX ou vazio)
        if (crp && crp.trim() !== '') {
            const crpRegex = /^\d{2}\/\d{4,6}$/;
            if (!crpRegex.test(crp.trim())) {
                return res.status(400).json({ error: 'CRP deve estar no formato XX/XXXXXX (ex: 06/123456)' });
            }
        }

        logger.info('[ACCOUNT] Atualizando perfil', { userId, name: name.trim() });

        const updateData = {
            name: name.trim(),
            crp: crp && crp.trim() !== '' ? crp.trim() : null,
            updated_at: new Date().toISOString()
        };

        const { data: updatedUser, error } = await supabase
            .from('users')
            .update(updateData)
            .eq('id', userId)
            .select('id, email, name, crp, plan, created_at')
            .single();

        if (error) {
            logger.error('[ACCOUNT] Erro ao atualizar perfil', { error: error.message, userId });
            return res.status(500).json({ error: 'Erro ao atualizar perfil' });
        }

        // Atualizar localStorage no client ao receber resposta
        logger.info('[ACCOUNT] Perfil atualizado com sucesso', { userId });

        res.json({
            success: true,
            message: 'Perfil atualizado com sucesso',
            user: {
                id: updatedUser.id,
                email: updatedUser.email,
                name: updatedUser.name,
                crp: updatedUser.crp,
                plan: updatedUser.plan,
                created_at: updatedUser.created_at
            }
        });

    } catch (error) {
        logger.error('[ACCOUNT] Erro ao atualizar perfil', { error: error.message });
        res.status(500).json({ error: 'Erro ao atualizar perfil' });
    }
});

/**
 * PUT /api/account/password
 * Alterar senha do usuário (requer senha atual)
 */
router.put('/password', authenticateRequest, async (req, res) => {
    try {
        const userId = req.user.userId;
        const { current_password, new_password } = req.body;

        if (!current_password || !new_password) {
            return res.status(400).json({ error: 'Senha atual e nova senha são obrigatórias' });
        }

        if (new_password.length < 8) {
            return res.status(400).json({ error: 'Nova senha deve ter no mínimo 8 caracteres' });
        }

        if (new_password.length > 128) {
            return res.status(400).json({ error: 'Nova senha deve ter no máximo 128 caracteres' });
        }

        if (current_password === new_password) {
            return res.status(400).json({ error: 'Nova senha deve ser diferente da atual' });
        }

        // Buscar hash atual
        const { data: user, error: fetchError } = await supabase
            .from('users')
            .select('id, password_hash')
            .eq('id', userId)
            .single();

        if (fetchError || !user) {
            return res.status(404).json({ error: 'Usuário não encontrado' });
        }

        // Verificar senha atual
        const isMatch = await bcrypt.compare(current_password, user.password_hash);
        if (!isMatch) {
            logger.warn('[ACCOUNT] Tentativa de alteração com senha incorreta', { userId });
            return res.status(401).json({ error: 'Senha atual incorreta' });
        }

        // Hash nova senha
        const newHash = await bcrypt.hash(new_password, 12);

        const { error: updateError } = await supabase
            .from('users')
            .update({ password_hash: newHash, updated_at: new Date().toISOString() })
            .eq('id', userId);

        if (updateError) {
            logger.error('[ACCOUNT] Erro ao atualizar senha', { error: updateError.message, userId });
            return res.status(500).json({ error: 'Erro ao atualizar senha' });
        }

        logger.info('[ACCOUNT] Senha alterada com sucesso', { userId });
        res.json({ success: true, message: 'Senha alterada com sucesso' });

    } catch (error) {
        logger.error('[ACCOUNT] Erro ao alterar senha', { error: error.message });
        res.status(500).json({ error: 'Erro ao alterar senha' });
    }
});

module.exports = router;

const express = require('express');
const bcrypt = require('bcrypt');
const {
  generateToken,
  generateRefreshToken,
  authenticateRequest
} = require('../middleware/auth');
const {
  saveToBoostspace,
  getFromBoostspace,
  updateInBoostspace
} = require('../services/database');
const logger = require('../config/logger');

const router = express.Router();

/**
 * POST /api/auth/signup
 * Criar nova conta
 */
router.post('/signup', async (req, res) => {
  try {
    const { email, password, name, crp } = req.body;

    // Validação básica
    if (!email || !password || !name) {
      return res.status(400).json({
        error: 'Email, senha e nome são obrigatórios'
      });
    }

    // Validar formato email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({
        error: 'Email inválido'
      });
    }

    // Validar senha (mínimo 8 caracteres)
    if (password.length < 8) {
      return res.status(400).json({
        error: 'Senha deve ter no mínimo 8 caracteres'
      });
    }

    logger.info('Tentativa de signup', { email });

    // Verificar se email já existe
    const existingUsers = await getFromBoostspace('users', { email });

    if (existingUsers && existingUsers.length > 0) {
      logger.warn('Email já cadastrado', { email });
      return res.status(409).json({
        error: 'Email já cadastrado'
      });
    }

    // Hash da senha
    const passwordHash = await bcrypt.hash(password, 12);

    // Criar usuário - ✅ GARANTIR created_at no formato ISO
    const now = new Date();
    const userData = {
      // id será gerado automaticamente pelo Supabase!
      email: email.toLowerCase(),
      password_hash: passwordHash,
      name,
      crp: crp || null,
      plan: 'free',
      subscription_status: 'inactive',
      created_at: now.toISOString(), // ✅ Formato ISO 8601
      updated_at: now.toISOString(),
      last_login: null
    };

    // 🐞 DEBUG: Verificar formato da data
    logger.info('🐞 DEBUG SIGNUP - userData antes de salvar:', {
      email: userData.email,
      created_at: userData.created_at,
      created_at_type: typeof userData.created_at,
      created_at_isValid: !isNaN(new Date(userData.created_at).getTime())
    });

    // Salvar no Boost.space
    const savedUser = await saveToBoostspace('users', userData);

    // 🐞 DEBUG: Verificar dados após salvar
    logger.info('🐞 DEBUG SIGNUP - savedUser retornado:', {
      id: savedUser.id,
      email: savedUser.email,
      created_at: savedUser.created_at,
      created_at_type: typeof savedUser.created_at
    });

    // Gerar tokens
    const token = generateToken(savedUser.id, 'free', savedUser.email);
    const refreshToken = generateRefreshToken(savedUser.id);

    logger.info('Usuário criado com sucesso', {
      userId: savedUser.id,
      email
    });

    // Retornar dados (sem senha!)
    res.status(201).json({
      message: 'Conta criada com sucesso',
      user: {
        id: savedUser.id,
        email: savedUser.email,
        name: savedUser.name,
        crp: savedUser.crp,
        plan: savedUser.plan
      },
      token,
      refreshToken
    });

  } catch (error) {
    logger.error('Erro no signup', { error: error.message });
    res.status(500).json({
      error: 'Erro ao criar conta',
      details: error.message
    });
  }
});

/**
 * POST /api/auth/login
 * Fazer login
 */
router.post('/login', async (req, res) => {
  try {
    const { email, password } = req.body;

    // Validação
    if (!email || !password) {
      return res.status(400).json({
        error: 'Email e senha são obrigatórios'
      });
    }

    logger.info('Tentativa de login', { email });

    // Buscar usuário
    const users = await getFromBoostspace('users', {
      email: email.toLowerCase()
    });

    if (!users || users.length === 0) {
      logger.warn('Email não encontrado', { email });
      return res.status(401).json({
        error: 'Email ou senha incorretos'
      });
    }

    const user = users[0];

    // Verificar senha
    const passwordMatch = await bcrypt.compare(password, user.password_hash);

    if (!passwordMatch) {
      logger.warn('Senha incorreta', { email });
      return res.status(401).json({
        error: 'Email ou senha incorretos'
      });
    }

    // ✅ Atualizar last_login (async, não bloqueia resposta)
    updateInBoostspace('users', user.id, {
      last_login: new Date().toISOString()
    }).catch(err => {
      logger.error('Erro ao atualizar last_login', { error: err.message, userId: user.id });
    });

    // 🔥 Atualizar Streak e Badges
    const { checkAndUpdateStreak } = require('../services/streakService');
    const { checkAndAwardBadges } = require('../services/badgeService');

    checkAndUpdateStreak(user.id, 'login').then(() => {
      return checkAndAwardBadges(user.id);
    }).catch(err => console.error('Erro gamification login:', err));

    // Gerar tokens
    const token = generateToken(user.id, user.plan, user.email);
    const refreshToken = generateRefreshToken(user.id);

    logger.info('Login bem-sucedido', {
      userId: user.id,
      email
    });

    res.json({
      message: 'Login realizado com sucesso',
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
        crp: user.crp,
        plan: user.plan
      },
      token,
      refreshToken
    });

  } catch (error) {
    logger.error('Erro no login', { error: error.message });
    res.status(500).json({
      error: 'Erro ao fazer login',
      details: error.message
    });
  }
});

