router.get('/series', authenticateRequest, async (req, res) => {
  try {
    const {
      difficulty_level,
      disorder_category
    } = req.query;

    logger.debug(`\n[Case Series] 📚 Listando séries disponíveis`);
    if (difficulty_level) logger.debug(`   Filtro: difficulty=${difficulty_level}`);
    if (disorder_category) logger.debug(`   Filtro: category=${disorder_category}`);

    let query = supabase
      .from('case_series')
      .select(`
        *,
        episodes:cases(count)
      `)
      .eq('status', 'active');

    if (difficulty_level) {
      query = query.eq('difficulty_level', difficulty_level);
    }

    if (disorder_category) {
      query = query.eq('disorder_category', disorder_category);
    }

    const { data: series, error } = await query.order('created_at', { ascending: false });

    if (error) throw error;

    // Adicionar contagem de episódios disponíveis
    const enriched = await Promise.all(series.map(async (s) => {
      const { count } = await supabase
        .from('cases')
        .select('*', { count: 'exact', head: true })
        .eq('series_id', s.id)
        .eq('status', 'active');

      return {
        ...s,
        episodes_available: count || 0
      };
    }));

    logger.debug(`[Case Series] ✅ ${series.length} séries encontradas\n`);

    res.json({
      success: true,
      series: enriched,
      total: series.length
    });

  } catch (error) {
    console.error('[Case Series] ❌ Erro ao listar séries:', error);
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

// ========================================
// GET /api/case/series/:series_id/next
// Retorna próximo episódio não visto da série
// ========================================
router.get('/series/:series_id/next', authenticateRequest, async (req, res) => {
  try {
    const { series_id } = req.params;
    const userId = req.user.userId;

    logger.debug(`\n[Case Series] 🎬 Próximo episódio da série ${series_id}, user=${userId}`);

    // 1. Buscar série
    const { data: series, error: seriesError } = await supabase
      .from('case_series')
      .select('*')
      .eq('id', series_id)
      .eq('status', 'active')
      .single();

    if (seriesError || !series) {
      return res.status(404).json({
        success: false,
        error: 'Série não encontrada'
      });
    }

    logger.debug(`[Case Series] 📚 Série: ${series.series_name}`);

    // 2. Buscar episódios já vistos pelo usuário
    const { data: seenEpisodes } = await supabase
      .from('user_case_interactions')
      .select('case_id')
      .eq('user_id', userId)
      .not('case_id', 'is', null);

    const seenCaseIds = seenEpisodes ? seenEpisodes.map(e => e.case_id) : [];

    logger.debug(`[Case Series] 👁️ Usuário já viu ${seenCaseIds.length} episódios desta série`);

    // 3. Buscar próximo episódio não visto
    let query = supabase
      .from('cases')
      .select('*')
      .eq('series_id', series_id)
      .eq('status', 'active')
      .order('episode_number', { ascending: true });

    if (seenCaseIds.length > 0) {
      query = query.not('id', 'in', `(${seenCaseIds.join(',')})`);
    }

    const { data: episodes, error: episodesError } = await query.limit(1);

    if (episodesError) throw episodesError;

    if (!episodes || episodes.length === 0) {
      logger.debug(`[Case Series] 🏁 Todos os episódios já foram vistos!`);
      return res.json({
        success: true,
        completed: true,
        message: `Parabéns! Você completou toda a série "${series.series_name}"`,
        series: series
      });
    }

    const nextEpisode = episodes[0];

    logger.debug(`[Case Series] ✅ Próximo episódio: #${nextEpisode.episode_number} - ${nextEpisode.episode_title}`);

    // Incrementar contador (assíncrono)
    supabase
      .from('cases')
      .update({ times_used: (nextEpisode.times_used || 0) + 1 })
      .eq('id', nextEpisode.id)
      .then(({ error }) => {
        if (error) console.error('[Case Series] Erro ao atualizar contador:', error.message);
      });

    res.json({
      success: true,
      series: series,
      episode: {
        ...nextEpisode,
        progress: {
          current: nextEpisode.episode_number,
          total: series.total_episodes,
          percentage: Math.round((nextEpisode.episode_number / series.total_episodes) * 100)
        }
      },
      case: nextEpisode.case_content,
      case_id: nextEpisode.id
    });

  } catch (error) {
    console.error('[Case Series] ❌ Erro:', error);
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

// ========================================
// GET /api/case/series/:series_id/progress
// Retorna progresso do usuário na série
// ========================================
router.get('/series/:series_id/progress', authenticateRequest, async (req, res) => {
  try {
    const { series_id } = req.params;
    const userId = req.user.userId;

    logger.debug(`\n[Case Series] 📊 Progresso na série ${series_id}, user=${userId}`);

    // Buscar série
    const { data: series } = await supabase
      .from('case_series')
      .select('*')
      .eq('id', series_id)
      .single();

    if (!series) {
      return res.status(404).json({ success: false, error: 'Série não encontrada' });
    }

    // Buscar todos os episódios da série
    const { data: allEpisodes } = await supabase
      .from('cases')
      .select('id, episode_number, episode_title')
      .eq('series_id', series_id)
      .eq('status', 'active')
      .order('episode_number');

    // Buscar episódios que o usuário viu
    const { data: userInteractions } = await supabase
      .from('user_case_interactions')
      .select('case_id, is_correct, created_at')
      .eq('user_id', userId)
      .in('case_id', allEpisodes.map(e => e.id));

    const seenIds = new Set(userInteractions?.map(i => i.case_id) || []);

    const progress = allEpisodes.map(ep => ({
      episode_number: ep.episode_number,
      episode_title: ep.episode_title,
      completed: seenIds.has(ep.id),
      interaction: userInteractions?.find(i => i.case_id === ep.id)
    }));

    const completed = progress.filter(p => p.completed).length;
    const total = allEpisodes.length;

    logger.debug(`[Case Series] ✅ Progresso: ${completed}/${total} episódios`);

    res.json({
      success: true,
      series: series,
      progress: {
        completed: completed,
        total: total,
        percentage: Math.round((completed / total) * 100),
        episodes: progress,
        is_complete: completed === total
      }
    });

  } catch (error) {
    console.error('[Case Series] ❌ Erro:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

module.exports = router;

// ========================================
// CHAT ROUTES - SCOPSY BACKEND (COM SUPABASE)
// ========================================

const express = require('express');
const router = express.Router();
const { authenticateRequest } = require('../middleware/auth');
const logger = require('../config/logger');
const OpenAI = require('openai');
const { createClient } = require('@supabase/supabase-js');

// Inicializar OpenAI
const openai = new OpenAI({
    apiKey: process.env.OPENAI_API_KEY
});

// Inicializar Supabase
const supabase = createClient(
    process.env.SUPABASE_URL,
    process.env.SUPABASE_SERVICE_ROLE_KEY
);

// IDs dos assistentes
const ASSISTANT_IDS = {
    orchestrator: process.env.ORCHESTRATOR_ID || 'asst_orchestrator',
    case: process.env.CASE_ID || 'asst_case',
    diagnostic: process.env.DIAGNOSTIC_ID || 'asst_diagnostic',
    journey: process.env.JOURNEY_ID || 'asst_journey',
    generator: process.env.GENERATOR_ID || 'asst_generator'
};

// ========================================
// POST /api/chat/message
// Enviar mensagem e salvar no Supabase
// ========================================

router.post('/message', authenticateRequest, async (req, res) => {
    try {
        const { message, assistantType = 'case', conversationId = null } = req.body;
        const userId = req.userId;

        // Validações
        if (!message || message.trim().length === 0) {
            return res.status(400).json({ error: 'Mensagem não pode estar vazia' });
        }

        if (message.length > 2000) {
            return res.status(400).json({ error: 'Mensagem muito longa (máximo 2000 caracteres)' });
        }

        if (!ASSISTANT_IDS[assistantType]) {
            return res.status(400).json({ error: 'Tipo de assistente inválido' });
        }

        logger.info(`📨 Nova mensagem de usuário ${userId} para ${assistantType}: ${message.substring(0, 50)}...`);

        // 1. OBTER OU CRIAR CONVERSA NO SUPABASE
        let conversation;
        
        if (conversationId) {
            // Buscar conversa existente
            const { data, error } = await supabase
                .from('chat_conversations')
                .select('*')
                .eq('id', conversationId)
                .eq('user_id', userId)
                .single();

            if (error || !data) {
                return res.status(404).json({ error: 'Conversa não encontrada' });
            }

            conversation = data;
        } else {
            // Criar nova conversa
            const { data, error } = await supabase
                .from('chat_conversations')
                .insert([{
                    user_id: userId,
                    assistant_type: assistantType,
                    title: message.substring(0, 50) + (message.length > 50 ? '...' : '')
                }])
                .select()
                .single();

            if (error) {
                logger.error('❌ Erro ao criar conversa:', error);
                return res.status(500).json({ error: 'Erro ao criar conversa' });
            }

            conversation = data;
            logger.info(`✅ Nova conversa criada: ${conversation.id}`);
        }

        // 2. SALVAR MENSAGEM DO USUÁRIO NO SUPABASE
        const { error: userMsgError } = await supabase
            .from('chat_messages')
            .insert([{
                conversation_id: conversation.id,
                role: 'user',
                content: message
            }]);

        if (userMsgError) {
            logger.error('❌ Erro ao salvar mensagem do usuário:', userMsgError);
        }

        // 3. OBTER OU CRIAR THREAD DO OPENAI
        let threadId = conversation.thread_id;

        if (!threadId) {
            logger.info(`🆕 Criando nova thread OpenAI`);
            const thread = await openai.beta.threads.create();
            threadId = thread.id;

            // Atualizar thread_id na conversa
            await supabase
                .from('chat_conversations')
                .update({ thread_id: threadId })
                .eq('id', conversation.id);

            logger.info(`✅ Thread criada: ${threadId}`);
        }

        // 4. ADICIONAR MENSAGEM À THREAD DO OPENAI
        await openai.beta.threads.messages.create(threadId, {
            role: 'user',
            content: message
        });

        logger.info(`✅ Mensagem adicionada à thread ${threadId}`);

        // 5. EXECUTAR ASSISTENTE
        const run = await openai.beta.threads.runs.create(threadId, {
            assistant_id: ASSISTANT_IDS[assistantType]
        });

        logger.info(`🤖 Assistente ${assistantType} iniciado (run: ${run.id})`);

        // 6. POLLING PARA AGUARDAR RESPOSTA
        let runStatus = await openai.beta.threads.runs.retrieve(threadId, run.id);
        let attempts = 0;
        const maxAttempts = 30;

        while (runStatus.status !== 'completed' && attempts < maxAttempts) {
            if (['failed', 'cancelled', 'expired'].includes(runStatus.status)) {
                throw new Error(`Assistente falhou com status: ${runStatus.status}`);
            }

            await new Promise(resolve => setTimeout(resolve, 1000));
            runStatus = await openai.beta.threads.runs.retrieve(threadId, run.id);
            attempts++;

            if (attempts % 5 === 0) {
                logger.info(`⏳ Aguardando resposta... (${attempts}s) - Status: ${runStatus.status}`);
            }
        }

        if (runStatus.status !== 'completed') {
            throw new Error('Timeout: Assistente demorou muito para responder');
        }

        logger.info(`✅ Assistente completou execução`);

        // 7. OBTER RESPOSTA DO ASSISTENTE
        const messages = await openai.beta.threads.messages.list(threadId, {
            limit: 1,
            order: 'desc'
        });

        const assistantMessage = messages.data[0];
        const responseText = assistantMessage.content[0].text.value;

        logger.info(`📤 Resposta do assistente: ${responseText.substring(0, 100)}...`);

        // 8. SALVAR RESPOSTA DO ASSISTENTE NO SUPABASE
        const { error: assistantMsgError } = await supabase
            .from('chat_messages')
            .insert([{
                conversation_id: conversation.id,
                role: 'assistant',
                content: responseText
            }]);

        if (assistantMsgError) {
            logger.error('❌ Erro ao salvar resposta do assistente:', assistantMsgError);
        }

        // 9. ATUALIZAR updated_at DA CONVERSA
        await supabase
            .from('chat_conversations')
            .update({ updated_at: new Date().toISOString() })
            .eq('id', conversation.id);

        // 10. RETORNAR RESPOSTA
        res.json({
            success: true,
            response: responseText,
            conversationId: conversation.id,
            assistantUsed: assistantType,
            timestamp: new Date().toISOString()
        });

    } catch (error) {
        logger.error('❌ Erro ao processar mensagem:', error);
        res.status(500).json({
            error: 'Erro ao processar mensagem',
            details: error.message
        });
    }
});

